import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;

public class Solution {
    public static long[][] solve(long[][] grid, long x, long y, long k) {
        ArrayList<long[]> submatrixRows = new ArrayList<>();

        for (int i = 0; i < k; i++) {
            int rowIdx = (int) (x + i);
            long[] subRow = Arrays.copyOfRange(grid[rowIdx], (int) y, (int) y + k);
            submatrixRows.add(subRow);
        }

        Collections.reverse(submatrixRows);

        for (int i = 0; i < k; i++) {
            int rowIdx = (int) (x + i);
            long[] newSubRow = submatrixRows.get(i);
            for (int j = 0; j < k; j++) {
                grid[rowIdx][y + j] = newSubRow[j];
            }
        }

        return grid;
    }
}
```

