import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class Solution {
    public static long[][] solve(long[][] grid, long x, long y, long k) {
        int m = grid.length;
        int n = grid[0].length;

        List<long[]> submatrixRows = new ArrayList<>();
        for (int i = 0; i < k; i++) {
            long[] row = new long[k];
            System.arraycopy(grid[(int)x + i], (int)y, row, 0, k);
            submatrixRows.add(row);
        }

        Collections.reverse(submatrixRows);

        for (int i = 0; i < k; i++) {
            long[] reversedRow = submatrixRows.get(i);
            System.arraycopy(reversedRow, 0, grid[(int)x + i], (int)y, k);
        }

        return grid;
    }
}
